  if (ac.containsKey('m2614.element1_covered'))  ctx_m2614['element1_covered']    = ac.get('m2614.element1_covered');
  if (ac.containsKey('m2614.element2_covered'))  ctx_m2614['element2_covered']    = ac.get('m2614.element2_covered');
  if (ac.containsKey('asset.compliance.encrypted')) ctx_m2614['asset_encrypted']  = ac.get('asset.compliance.encrypted');
  if (ac.containsKey('asset.managed'))           ctx_m2614['managed']             = ac.get('asset.managed');
  if (ac.containsKey('asset.last_seen'))         ctx_m2614['asset_last_seen']     = ac.get('asset.last_seen');
}
